@import url('https://fonts.googleapis.com/css2?family=DM+Sans:wght@400;500;600;700;800&display=swap');

* {
  box-sizing: border-box;
}

body {
  margin: 0;
  padding: 0;
  font-family: 'DM Sans', sans-serif;
}

.auth-container {
  display: flex;
  width: 100%;
  min-height: 100vh;
  font-family: 'DM Sans', sans-serif;
}

.auth-left {
  width: 40%;
  min-height: 100vh;
  background: linear-gradient(160deg, #0a6b6b, #0e9090, #1aadad);
  background-image: 
    repeating-linear-gradient(
      45deg,
      rgba(255, 255, 255, 0.04) 1px,
      transparent 1px,
      transparent 28px
    ),
    linear-gradient(160deg, #0a6b6b, #0e9090, #1aadad);
  background-size: 28px 28px, 100% 100%;
  display: flex;
  flex-direction: column;
  min-height: 100vh;
  padding: 3rem 2.5rem;
}

.auth-left-content {
  flex: 1;
  display: flex;
  flex-direction: column;
  justify-content: center;
  position: relative;
  z-index: 2;
}

.auth-left h2, .auth-left .auth-headline {
  font-family: 'DM Sans', sans-serif;
  font-size: 2.2rem;
  font-weight: 800;
  line-height: 1.2;
  color: #ffffff;
  letter-spacing: -0.02em;
  margin-bottom: 0.75rem;
}

.auth-left .auth-subtext {
  font-size: 0.92rem;
  color: rgba(255,255,255,0.65);
  line-height: 1.6;
  margin-top: 0.75rem;
  max-width: 340px;
}

.feature-list {
  margin-top: 2rem;
  display: flex;
  flex-direction: column;
  gap: 0.65rem;
}

.feature-item {
  background: rgba(255,255,255,0.15);
  border: 1px solid rgba(255,255,255,0.25);
  backdrop-filter: blur(8px);
  border-radius: 999px;
  padding: 0.5rem 1.1rem;
  font-size: 0.84rem;
  font-weight: 500;
  color: #ffffff;
  display: inline-flex;
  align-items: center;
  gap: 0.5rem;
  width: fit-content;
}

.feature-item::before {
  content: '';
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: rgba(255,255,255,0.9);
  flex-shrink: 0;
}

.mock-visual {
  background: rgba(255,255,255,0.1);
  border: 1px solid rgba(255,255,255,0.18);
  border-radius: 18px;
  padding: 1.4rem 1.6rem;
  margin-top: 1.5rem;
  backdrop-filter: blur(10px);
}

.mock-bar {
  background: rgba(255,255,255,0.8);
  height: 10px;
  border-radius: 999px;
  margin-bottom: 0.6rem;
  width: 70%;
}

.mock-bar.short {
  width: 45%;
  background: rgba(255,255,255,0.55);
}

.mock-wave {
  display: flex;
  align-items: flex-end;
  gap: 5px;
  height: 64px;
  margin-top: 1rem;
}

.wave-block { 
  flex: 1; 
  border-radius: 4px 4px 2px 2px;
}

.wave-block:nth-child(1) { background: #ff6b6b; height: 35% !important; }
.wave-block:nth-child(2) { background: #ff9f43; height: 90% !important; }
.wave-block:nth-child(3) { background: #ffd32a; height: 55% !important; }
.wave-block:nth-child(4) { background: #0be881; height: 100% !important; }
.wave-block:nth-child(5) { background: #00d2d3; height: 30% !important; }
.wave-block:nth-child(6) { background: #54a0ff; height: 70% !important; }
.wave-block:nth-child(7) { background: #a29bfe; height: 90% !important; }
.wave-block:nth-child(8) { background: #fd79a8; height: 42% !important; }

@keyframes waveAnim {
  0%, 100% { transform: scaleY(1);   opacity: 1;    }
  50%       { transform: scaleY(0.7); opacity: 0.75; }
}

.wave-block:nth-child(odd)  { animation: waveAnim 2.2s ease-in-out infinite; }
.wave-block:nth-child(even) { animation: waveAnim 2.2s ease-in-out infinite 0.4s; }

.mock-card {
  position: absolute;
  bottom: 25%;
  left: 50%;
  transform: translateX(-50%) rotate(-3deg);
  background: white;
  border-radius: 16px;
  padding: 1rem;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.25);
  width: 280px;
}

.mock-card-image {
  width: 100%;
  height: 160px;
  background: linear-gradient(135deg, #e5e7eb 25%, #f3f4f6 25%, #f3f4f6 50%, #e5e7eb 50%, #e5e7eb 75%, #f3f4f6 75%);
  background-size: 20px 20px;
  border-radius: 8px;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #9ca3af;
  font-size: 0.75rem;
}

.mock-card-blocks {
  display: flex;
  gap: 8px;
  margin-top: 10px;
}

.mock-block {
  height: 8px;
  background: #e5e7eb;
  border-radius: 4px;
}

.mock-block:nth-child(1) { width: 30%; }
.mock-block:nth-child(2) { width: 50%; }
.mock-block:nth-child(3) { width: 20%; }

.floating-badge {
  position: absolute;
  background: white;
  border-radius: 999px;
  padding: 0.3rem 0.8rem;
  font-size: 0.72rem;
  font-weight: 600;
  box-shadow: 0 2px 8px rgba(0, 0, 0, 0.1);
  color: #374151;
  z-index: 3;
}

.badge-slack {
  top: 20%;
  left: 15%;
}

.badge-google-ads {
  top: 30%;
  right: 10%;
}

.badge-zendesk {
  bottom: 40%;
  left: 5%;
}

.badge-shopify {
  bottom: 30%;
  right: 8%;
}

.auth-left .auth-copyright {
  font-size: 0.72rem;
  color: rgba(255,255,255,0.35);
  margin-top: 0;
  padding-top: 1rem;
}

.auth-right {
  width: 60%;
  background: #f4f6f8;
  display: flex;
  align-items: center;
  justify-content: center;
  min-height: 100vh;
}

.auth-card {
  background: #ffffff;
  border: 1px solid #e5e7eb;
  border-radius: 20px;
  padding: 2.5rem 2.25rem;
