  padding: 0.6rem;
  font-size: 0.82rem;
  font-weight: 500;
  color: #374151;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.4rem;
  cursor: pointer;
  transition: all 0.2s ease;
  font-family: 'DM Sans', sans-serif;
}

.social-btn:hover {
  background: #f9fafb;
  border-color: #d1d5db;
}

.social-btn svg {
  width: 16px;
  height: 16px;
}

.switch-auth {
  font-size: 0.84rem;
  color: #6b7280;
  text-align: center;
  margin-top: 1.2rem;
}

.switch-auth button {
  background: none;
  border: none;
  color: #0e9090;
  font-weight: 700;
  cursor: pointer;
  text-decoration: none;
  padding: 0;
}

.switch-auth button:hover {
  text-decoration: underline;
}

.error-message {
  background: #fef2f2;
  border: 1px solid #fecaca;
  color: #b91c1c;
  border-radius: 10px;
  padding: 0.65rem 0.9rem;
  font-size: 0.82rem;
  margin-bottom: 1rem;
}

.success-message {
  background: #f0fdf4;
  border: 1px solid #bbf7d0;
  color: #15803d;
  border-radius: 10px;
